// Excel columns mapping with Cloudinary support
const rows = $input.all();
const CLOUDINARY_BASE = 'https://res.cloudinary.com/city-frame-collective/image/upload';

const rows = $input.all();
const products = rows.map((row, index) => {
  const data = row.json;

  // Convert image URL to Cloudinary format
  const getImageUrl = (url) => {
    if (!url) return null;

    // If already Cloudinary URL, use as-is
    if (url.includes('res.cloudinary.com')) {
      return url;
    }

    // If Google Drive URL, convert to uc?id= format
    if (url.includes('drive.google.com')) {
      const match = url.match(/\/d\/([a-zA-Z0-9-_]+)/);
      return match ? `https://drive.google.com/uc?id=${match[1]}` : null;
    }

    return url;
  };

  // Parse tags from comma-separated string
  const parseTags = (tagString) => {
    if (!tagString) return [];
    return tagString.split(',').map(t => t.trim().toLowerCase());
  };

  return {
    id: data.id || index + 1,
    city: data.city || '',
    country: data.country || '',
    series: data.series || '',
    price: parseInt(data['price usd']) || 349,
    description: data.inspiration || '',
    images: {
      hero: getImageUrl(data['hero image link']) || ''
    },
    etsyUrl: data['etsy listing link'] || '',
    tags: parseTags(data['etsy tags']) || []
  };
});

return { products };

// Prepare final JSON structure
const data = $input.first().json;
const finalJson = {
  products: data.products,
  lastUpdated: new Date().toISOString(),
  totalProducts: data.products.length
};

return JSON.stringify(finalJson, null, 2);
